import{_ as o,o as r,c as a,a2 as n}from"./chunks/framework.DnrXFDHb.js";const d=JSON.parse('{"title":"G14: 新業務展望 - 產品趨勢研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/經營審計/3189_景碩/20260423/G14_新業務展望_產品趨勢研究員.md","filePath":"審計報告庫/經營審計/3189_景碩/20260423/G14_新業務展望_產品趨勢研究員.md"}'),i={name:"審計報告庫/經營審計/3189_景碩/20260423/G14_新業務展望_產品趨勢研究員.md"};function s(l,t,e,g,A,_){return r(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="g14-新業務展望-產品趨勢研究員-審計報告" tabindex="-1">G14: 新業務展望 - 產品趨勢研究員 審計報告 <a class="header-anchor" href="#g14-新業務展望-產品趨勢研究員-審計報告" aria-label="Permalink to &quot;G14: 新業務展望 - 產品趨勢研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>公司在最近三年中是否有增加新的業務展望或第二成長曲線？其技術儲備與市場佈局進度為何？</p><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p><strong>評級：S（優質）</strong>。根據截至2026年Q1最新公開數據，景碩正處於ABF載板產業十年黃金周期的起點，其第二成長曲線—AI ASIC高階載板業務—已從「研發期」正式跨入「樣品送審暨小量出貨期」，成功取得Google TPU、Meta MTIA及AWS Trainium等美系CSP的Design-win實績，技術布局高度符合產業大勢。</p><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>賽道趨勢對位</strong>：AI驅動ABF載板市場2025-2030年CAGR達16.1%（美系外資預估），顯著高於前五年9%的增速；2030年TAM預估達160億美元。景碩主攻之AI ASIC載板為其中增速最快的細分領域，2026年全球AI相關ABF需求預估暴增92%。</li><li><strong>Design-win實績</strong>：已取得Google TPU及Meta AI加速器訂單（2026年Q1小量出貨），預計下半年啟動AWS Trainium正式供貨。美系AI客戶CPU供貨率由10%躍升至50%。</li><li><strong>資本支出規模</strong>：宣布235億元三年擴產計畫（史上最大），於楊梅六廠擴充ABF產能，月產能目標由4000萬顆提升至5000萬顆，2027年新產能陸續開出。</li><li><strong>營收與獲利驗證</strong>：2026年Q1合併營收111.05億元，年增28.8%，創同期新高；3月自結EPS 0.58元，年增81.25%。法人預估2026年EPS翻倍至7.75-8.85元。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><p><strong>一、第二成長曲線的定位與市場缺口</strong></p><p>景碩的傳統核心業務為BT載板（記憶體、手機應用），佔營收約35%。其第二成長曲線明確指向<strong>AI ASIC高階ABF載板</strong>。根據供應鏈報告，Nvidia新一代Rubin晶片量產後（2026年Q2），ABF載板尺寸將從Blackwell的81.5x74.8mm²放大至100x91mm²，層數由12-14L提升至18-20L。在層數與面積雙重拉升下，整體面積需求預估成長3-4倍。</p><p><strong>二、技術儲備的真實門檻</strong></p><p>景碩為全球Flip Chip前三大供應商，在CPU載板市占率高達50%，是Intel與AMD的長期合作夥伴。其高層數ABF技術門檻體現在：(1) T-glass（高階玻纖布）供應嚴重短缺，日本Nittobo擴產至2027年Q3才見效，2026全年供給缺口持續；(2) 景碩已在高層數（16-20層以上）ABF載板掌握量產能力； (3) ABF稼動率由86%拉升至95%，反映客戶CPU供貨率大幅提升，產能接近滿載。</p><p><strong>三、進度驗證：從研發到收割</strong></p><p>營收數據清晰驗證布局進度：2026年1月營收39.61億元（月增7.4%、年增54.94%）創歷史新高；3月營收39.39億元（年增25.06%）。2025年全年EPS 3.51元，較前一年大增31.6倍；2026年Q1自結獲利已大幅超越市場預期。景碩管理層明確提出2026年業績雙位數成長、ABF載板年成長30%的目標。</p><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><p><strong>多頭觀點</strong>：景碩的第二成長曲線布局順應AI基礎設施投資的結構性趨勢。美系CSP（Google、Meta、AWS）未調降資本支出，加上AI Agent帶動通用伺服器CPU需求上揚，ABF載板供需缺口預計延伸至2028年（缺口達13%）。報價漲勢正從成本推升轉為需求拉動，此結構性轉變對景碩定價權構成重大利多。</p><p><strong>空頭疑慮（華爾街Skepticism）</strong>：</p><ol><li><strong>估值壓力</strong>：當前本益比約55倍、Forward PE約35倍，已提前反映2026-2027年獲利成長。若ASIC訂單遞延或AI資本支出週期性放緩，估值修正風險極大。</li><li><strong>產能擴張的折舊壓力</strong>：235億元資本支出將於2027年起陸續攤提折舊，短期內恐壓抑毛利率提升幅度。</li><li><strong>單一材料風險</strong>：T-glass斷鏈既是定價權來源也是產能瓶頸，若Nittobo擴產不如預期，可能反噬出貨量。</li><li><strong>集中度風險</strong>：AI ASIC訂單高度集中於前幾大CSP客戶，單一客戶訂單變動將顯著影響業績波動。</li></ol><p><strong>綜合建議</strong>：景碩新業務方向正確且具備扎實的競爭護城河（技術門檻+客戶黏著度），但當前股價已大幅反映樂觀預期。投資人應關注2026年Q2 Rubin量產後實際Design-win訂單規模，以及下半年T-glass缺口對出貨的實際影響。若拉回至300-320元區間（2026年EPS 8.85元的36倍PE），具中長期布局價值。</p><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li><strong>yf_info 查詢</strong>: yf_info 3189.TW (市值2523.9億、Gross Margins 21.13%、EPS TTM 3.39、Forward EPS 13.60)</li><li><strong>數據採集器查詢</strong>: revenue 3189 2023-01-01 2026-04-23 (2026年Q1營收111.05億、年增28.8%)</li><li><strong>經濟日報</strong>: 景碩2026年台灣六廠擴ABF載板產能，AI需求供不應求（2026/03/12）</li><li><strong>理財周刊</strong>: ABF大缺貨+ASIC新單收割，目標價上看450元</li><li><strong>今周刊</strong>: ABF載板三雄分析（2026/04/21）</li><li><strong>美系外資報告</strong>: ABF載板2025-2030年CAGR 16.1%，TAM 2030年達160億美元</li><li><strong>供應鏈數據</strong>: Nvidia Rubin晶片ABF載板尺寸100x91mm²，層數18-20L</li><li><strong>Yahoo奇摩股市</strong>: 景碩今年業績看兩位數成長，ABF載板需求強續擴產（2026/03/12）</li><li><strong>Threads</strong>: 報告預估2026年全球AI相關ABF需求暴增92%</li></ul>',21)])])}const p=o(i,[["render",s]]);export{d as __pageData,p as default};
